import re
import socket
import urllib.parse
def task_func(myString):
    url_pattern = r'https?://[^\s/$.?          
    urls = re.findall(url_pattern, myString)

    domain_ip_map = {}

    for url in urls:
        try:
            parsed_url = urllib.parse.urlparse(url)
            domain = parsed_url.netloc

            if domain in domain_ip_map:
                continue

            ip_address = socket.gethostbyname(domain)
            domain_ip_map[domain] = ip_address
        except socket.gaierror:
            domain_ip_map[domain] = None

    return domain_ip_map

import subprocess
import psutil
import time
def task_func(process_name: str) -> str:
    is_running = any([proc for proc in psutil.process_iter() if proc.name() == process_name])

    if is_running:
        for proc in psutil.process_iter():
            if proc.name() == process_name:
                proc.terminate()
                time.sleep(5)
        subprocess.Popen(process_name)
        return f"Process found. Restarting {process_name}."
    else:
        subprocess.Popen(process_name)
        return f"Process not found. Starting {process_name}."

