import os
import shutil
BACKUP_DIR = '/tmp/backup'
def task_func(directory):
    if not os.path.exists(BACKUP_DIR):
        return f'Backup directory {BACKUP_DIR} does not exist. Cannot rollback update.'

    backup_dir_path = os.path.join(BACKUP_DIR, os.path.basename(directory))
    if not os.path.exists(backup_dir_path):
        return f'Backup of directory {directory} does not exist. Cannot rollback update.'

    try:
        shutil.rmtree(directory)
    except FileNotFoundError:
        pass                                                      

    try:
        shutil.copytree(backup_dir_path, directory)
    except Exception as e:
        return f'Failed to restore directory {directory}: {str(e)}'

    return directory

