import os
import shutil
import fnmatch
def task_func(source_directory, destination_directory, file_pattern):
    if not os.path.exists(source_directory):
        raise FileNotFoundError(f"Source directory '{source_directory}' does not exist.")
    if not os.path.exists(destination_directory):
        os.makedirs(destination_directory)                                                     

    moved_files = []

    for filename in os.listdir(source_directory):
        if fnmatch.fnmatch(filename, file_pattern):
            source_file_path = os.path.join(source_directory, filename)
            destination_file_path = os.path.join(destination_directory, filename)

            if os.path.isfile(source_file_path):
                shutil.move(source_file_path, destination_file_path)
                moved_files.append(filename)

    return moved_files

import json
import csv
import os
import base64
def task_func(raw_string, filename, output_dir):
    try:
        decoded_json = base64.b64decode(raw_string).decode('utf-8')
    except Exception as e:
        raise ValueError(f"Failed to decode base64 string: {e}")

    try:
        data = json.loads(decoded_json)
    except json.JSONDecodeError as e:
        raise ValueError(f"Failed to parse JSON: {e}")

    if not isinstance(data, list) or not all(isinstance(item, dict) for item in data):
        raise ValueError("JSON data must be a list of dictionaries.")

    os.makedirs(output_dir, exist_ok=True)

    file_path = os.path.join(output_dir, f"{filename}.csv")

    try:
        with open(file_path, mode='w', newline='', encoding='utf-8') as csv_file:
            headers = data[0].keys()
            writer = csv.DictWriter(csv_file, fieldnames=headers)

            writer.writeheader()
            writer.writerows(data)
    except Exception as e:
        raise IOError(f"Failed to write CSV file: {e}")

    return file_path

